    entry start()
        emit @{vm_resume}(L, 0;
            ok = done,
            yielded = yielded,
            runtime_error = err,
            oom = oom)
    end
    block done(nres: i32) return nres end
    block yielded(nres: i32) return -100 - nres end
    block err(code: i32) return -200 - code end
    block oom() return -999 end
    end
end
